#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
const int N = 1e4+5;
int n,B,bel[N],Rt[N],cnt;
int st[N],top;vector<int> g[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS(int u,int fa){
    int old=top;
    for(int v:g[u])if(v^fa){
        DFS(v,u);
        if(top-old>=B){
            Rt[++cnt]=u;
            while(top>old)bel[st[top--]]=cnt;
        }
    }st[++top]=u;return;
}
int main(){
    n=read(),B=read();
    for(int i=1;i<n;i++){
        int x=read(),y=read();
        g[x].pb(y),g[y].pb(x);
    }DFS(1,0);
    if(!cnt)Rt[++cnt]=1;
    while(top)bel[st[top--]]=cnt;
    cout<<cnt<<"\n";
    for(int i=1;i<=n;i++)
        cout<<bel[i]<<" ";cout<<"\n";
    for(int i=1;i<=cnt;i++)
        cout<<Rt[i]<<" ";cout<<"\n";
    return 0;
}
